{
  "cmd": "powershell -Command \"Get-ChildItem -Path (Join-Path $env:USERPROFILE 'Desktop'), 'C:\\Users\\Public\\Desktop' -Filter '*.lnk' -ErrorAction SilentlyContinue | Select-Object Name, FullName | Format-Table -AutoSize\"",
  "msg": "System failed to launch the Nexus App. Checking desktop for links..."
}

{
  "cmd": "powershell -Command \"Start-Process -FilePath 'C:\\Users\\Kashif\\Desktop\\Nexus App.lnk'\"",
  "msg": "Found the Sonata App on your desktop, launching now..."
}

{
  "cmd": "powershell -Command \"Start-Process -FilePath 'C:\\Program Files\\Nexus\\Nexus App.exe'\"",
  "msg": "The Nexus App was not found directly on your desktop, but we should be able to start it from the program files directory."
}

{
  "cmd": "type memory\memory.txt",
  "msg": "Checking our Stored Memory for the Nexus App path..."
}
